      let c01 = srgb_at(spx + vec2<i32>(-1, 0), accumDim);
      let c21 = srgb_at(spx + vec2<i32>(1, 0), accumDim);
      let c02 = srgb_at(spx + vec2<i32>(-1, 1), accumDim);
      let c12 = srgb_at(spx + vec2<i32>(0, 1), accumDim);
